"""incident_classifier.py -- taxonomy-driven incident classification."""
from __future__ import annotations
from dataclasses import dataclass
from typing import Optional
import operator
import yaml


@dataclass
class IncidentClass:
    category_id: str
    type_id: str
    label: str
    severity: str
    owner_team: str
    runbook_url: str
    notify_legal: bool = False
    notify_ciso: bool = False


def load_taxonomy(path: str = "incident-taxonomy.yaml") -> dict:
    with open(path) as f:
        return yaml.safe_load(f)["taxonomy"]


OPS = {">" : operator.gt, "<": operator.lt, ">=": operator.ge, "<=": operator.le}


def _evaluate_rule(rule: str, signals: dict) -> bool:
    """Evaluate a simple threshold or boolean rule against live signals."""
    import re
    # Try: metric OP number
    m = re.match(r"([\w\.]+)\s*([<>]=?)\s*([\d\.]+)", rule)
    if m:
        metric, op, threshold = m.group(1), m.group(2), float(m.group(3))
        val = signals.get(metric)
        if val is not None:
            return OPS[op](float(val), threshold)
    # Boolean: any named token that is True in signals
    for token in re.findall(r"[a-z_]+", rule):
        if signals.get(token) is True:
            return True
    return False


def classify_incident(
    signals: dict,
    taxonomy: dict,
    override_severity: Optional[str] = None,
) -> Optional[IncidentClass]:
    """Return first matching IncidentClass, or None if no rule matches."""
    for cat in taxonomy["categories"]:
        for inc_type in cat["types"]:
            if _evaluate_rule(inc_type["detection_signal"], signals):
                sev = override_severity or cat["default_severity"]
                if signals.get("user_harm_confirmed") or signals.get("data_breach_confirmed"):
                    sev = cat["escalation_severity"]
                return IncidentClass(
                    category_id=cat["id"],
                    type_id=inc_type["id"],
                    label=inc_type["label"],
                    severity=sev,
                    owner_team=cat["owner_team"],
                    runbook_url=inc_type["runbook"],
                    notify_legal=cat.get("notify_legal", False),
                    notify_ciso=cat.get("notify_ciso", False),
                )
    return None


if __name__ == "__main__":
    tax = load_taxonomy()
    # Simulate a tool-call retry loop
    result = classify_incident({"agent.step_count": 28}, tax)
    if result:
        print(f"Classified: {result.label} ({result.severity}) -> {result.owner_team}")
        print(f"Runbook: {result.runbook_url}")
